-- Buscar ID da empresa B I IMOVEIS LTDA
SELECT id, name FROM companies WHERE name LIKE '%B I IMOVEIS%';

-- Atualizar companyId das vendas importadas
UPDATE sales 
SET companyId = (SELECT id FROM companies WHERE name LIKE '%B I IMOVEIS%' LIMIT 1)
WHERE companyId = 'default_company';

-- Verificar quantas vendas foram atualizadas
SELECT COUNT(*) as total_atualizadas FROM sales 
WHERE companyId = (SELECT id FROM companies WHERE name LIKE '%B I IMOVEIS%' LIMIT 1);

